# Drizzle Configuration

The `drizzle.config.ts` file at your project root configures all drizzle-kit CLI commands.

## Minimal Configuration

```typescript
// drizzle.config.ts
import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  dialect: 'postgresql',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: process.env.DATABASE_URL!,
  },
});
```

## Full Configuration Reference

```typescript
import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  // ─── Required ──────────────────────────────────────
  dialect: 'postgresql',              // 'postgresql' | 'mysql' | 'sqlite' | 'turso' | 'singlestore' | 'mssql'
  schema: './src/db/schema.ts',       // Path or glob to schema files

  // ─── Output ────────────────────────────────────────
  out: './drizzle',                   // Migration output directory (default: 'drizzle')

  // ─── Database Connection ───────────────────────────
  dbCredentials: {
    url: process.env.DATABASE_URL!,   // URL format
    // OR individual fields:
    // host: 'localhost',
    // port: 5432,
    // user: 'postgres',
    // password: 'password',
    // database: 'mydb',
    // ssl: true,
  },

  // ─── Migration Table ───────────────────────────────
  migrations: {
    table: '__drizzle_migrations',    // Custom migration tracking table name
    schema: 'public',                 // PostgreSQL schema for migration table
  },

  // ─── Filters ───────────────────────────────────────
  tablesFilter: ['users', 'posts', 'app_*'],  // Glob filter for push/pull
  schemaFilter: ['public', 'auth'],            // PostgreSQL schema names
  extensionsFilters: ['postgis'],              // Ignore extension tables

  // ─── Behavior ──────────────────────────────────────
  strict: true,                       // Require confirmation for destructive changes
  verbose: true,                      // Print generated SQL statements
  breakpoints: true,                  // Add statement breakpoints (default: true)

  // ─── Introspect ────────────────────────────────────
  introspect: {
    casing: 'camel',                  // 'preserve' | 'camel' — column key casing on pull
  },

  // ─── Driver Override ───────────────────────────────
  // driver: 'aws-data-api',          // 'aws-data-api' | 'd1-http' | 'pglite'
});
```

## Configuration by Database

### PostgreSQL

```typescript
export default defineConfig({
  dialect: 'postgresql',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: 'postgres://user:pass@localhost:5432/mydb',
  },
});
```

### MySQL

```typescript
export default defineConfig({
  dialect: 'mysql',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: 'mysql://user:pass@localhost:3306/mydb',
  },
});
```

### SQLite

```typescript
export default defineConfig({
  dialect: 'sqlite',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: './sqlite.db',              // File path
    // url: ':memory:',              // In-memory
  },
});
```

### Turso

```typescript
export default defineConfig({
  dialect: 'turso',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: process.env.TURSO_DATABASE_URL!,
    authToken: process.env.TURSO_AUTH_TOKEN!,
  },
});
```

### Neon Serverless

```typescript
export default defineConfig({
  dialect: 'postgresql',
  schema: './src/db/schema.ts',
  out: './drizzle',
  dbCredentials: {
    url: process.env.NEON_DATABASE_URL!,
  },
});
```

### Cloudflare D1

```typescript
export default defineConfig({
  dialect: 'sqlite',
  schema: './src/db/schema.ts',
  out: './drizzle',
  driver: 'd1-http',
  dbCredentials: {
    accountId: process.env.CF_ACCOUNT_ID!,
    databaseId: process.env.CF_D1_DATABASE_ID!,
    token: process.env.CF_API_TOKEN!,
  },
});
```

## Schema Path Patterns

```typescript
// Single file
schema: './src/db/schema.ts'

// Directory (all .ts files)
schema: './src/db/schema'

// Glob pattern
schema: './src/**/*.schema.ts'

// Multiple explicit files
schema: ['./src/db/users.ts', './src/db/posts.ts']
```

## Multiple Config Files

Maintain separate configs per environment:

```bash
# Development
npx drizzle-kit generate --config=drizzle.dev.config.ts

# Production
npx drizzle-kit migrate --config=drizzle.prod.config.ts

# Staging
npx drizzle-kit push --config=drizzle.staging.config.ts
```

## Configuration Options Reference

| Option | Type | Required | Default | Purpose |
|--------|------|----------|---------|--------|
| `dialect` | string | Yes | — | Database type |
| `schema` | string/string[] | Yes | — | Schema file path(s) |
| `out` | string | No | `'drizzle'` | Migration output directory |
| `dbCredentials` | object | Yes* | — | Database connection (*not needed for generate-only) |
| `driver` | string | No | auto | Override driver detection |
| `strict` | boolean | No | `false` | Confirm destructive ops |
| `verbose` | boolean | No | `true` | Print SQL output |
| `breakpoints` | boolean | No | `true` | Statement breakpoint markers |
| `tablesFilter` | string[] | No | all | Glob filter for tables |
| `schemaFilter` | string[] | No | all | PostgreSQL schema filter |
| `extensionsFilters` | string[] | No | none | Ignore extension tables |
| `migrations.table` | string | No | `'__drizzle_migrations'` | Migration tracking table |
| `migrations.schema` | string | No | `'drizzle'` | Migration table schema |
| `introspect.casing` | string | No | `'preserve'` | Column casing on pull |

## Environment Variables

| Variable | Purpose | Example |
|----------|---------|--------|
| `DATABASE_URL` | Main connection string | `postgres://user:pass@localhost:5432/mydb` |
| `TURSO_DATABASE_URL` | Turso connection URL | `libsql://db-name.turso.io` |
| `TURSO_AUTH_TOKEN` | Turso auth token | `eyJ...` |
| `CF_ACCOUNT_ID` | Cloudflare account ID | `abc123` |
| `CF_D1_DATABASE_ID` | Cloudflare D1 database ID | `def456` |
| `CF_API_TOKEN` | Cloudflare API token | `token123` |
